import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from "@/components/ui/dialog";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Button } from "@/components/ui/button";
import { ExternalLink, MapPin, Globe, Phone, Mail, Star } from "lucide-react";

interface LandmarkPreviewDialogProps {
  landmarkId: string | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function LandmarkPreviewDialog({
  landmarkId,
  open,
  onOpenChange,
}: LandmarkPreviewDialogProps) {
  const { t } = useTranslation();
  const [imgError, setImgError] = useState(false);

  useEffect(() => {
    setImgError(false);
  }, [landmarkId]);

  const { data, isLoading, error } = useQuery({
    queryKey: ["landmark-preview", landmarkId],
    queryFn: async () => {
      if (!landmarkId) return null;
      const { data, error } = await supabase
        .from("restaurants")
        .select(
          "id, name, name_en, name_pt, address, city, country, image_url, phone, email, rating, type, category, landmark_types, cuisine_types, dining_features, hotel_features, description, description_en, description_pt"
        )
        .eq("id", landmarkId)
        .maybeSingle();
      if (error) throw error;
      return data as any;
    },
    enabled: open && !!landmarkId,
  });

  const cover = !imgError && data?.image_url ? data.image_url : null;

  const subtypes = (() => {
    if (!data) return [];
    const cat = data.category;
    if (cat === "architecture") return data.landmark_types || [];
    if (cat === "food") return data.cuisine_types || [];
    if (cat === "hotel") return data.hotel_features || [];
    return data.type || [];
  })();

  const description =
    data?.description || data?.description_en || data?.description_pt || "";

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[85vh] overflow-y-auto p-0">
        {isLoading || !data ? (
          <div className="p-6 space-y-3">
            <Skeleton className="h-48 w-full rounded-md" />
            <Skeleton className="h-6 w-2/3" />
            <Skeleton className="h-4 w-full" />
            <Skeleton className="h-4 w-5/6" />
          </div>
        ) : (
          <>
            {cover && (
              <div className="relative w-full h-48 bg-muted">
                <img
                  src={cover}
                  alt={data.name}
                  className="w-full h-full object-cover"
                  onError={() => setImgError(true)}
                />
              </div>
            )}
            <div className="p-6 space-y-4">
              <DialogHeader className="space-y-1">
                <DialogTitle className="text-xl">{data.name}</DialogTitle>
                {(data.name_en || data.name_pt) && (
                  <DialogDescription className="text-xs">
                    {[data.name_en, data.name_pt].filter(Boolean).join(" · ")}
                  </DialogDescription>
                )}
              </DialogHeader>

              {/* Meta */}
              <div className="flex flex-wrap gap-3 text-xs text-muted-foreground">
                {data.address && (
                  <span className="flex items-center gap-1">
                    <MapPin className="h-3.5 w-3.5" />
                    {[data.city, data.address].filter(Boolean).join(" · ")}
                  </span>
                )}
                {data.rating != null && (
                  <span className="flex items-center gap-1">
                    <Star className="h-3.5 w-3.5 fill-current text-primary" />
                    {Number(data.rating).toFixed(1)}
                  </span>
                )}
              </div>

              {/* Tags */}
              <div className="flex flex-wrap gap-1.5">
                {data.category && (
                  <Badge variant="default" className="text-xs">
                    {String(t(`category.${data.category}`, { defaultValue: data.category }))}
                  </Badge>
                )}
                {subtypes.slice(0, 8).map((tg: string, i: number) => (
                  <Badge key={i} variant="secondary" className="text-xs">
                    {tg}
                  </Badge>
                ))}
              </div>

              {/* Description */}
              {description && (
                <div className="text-sm leading-relaxed text-foreground/90">
                  <p className="whitespace-pre-line line-clamp-[10]">{description}</p>
                </div>
              )}

              {/* Contacts */}
              <div className="grid grid-cols-1 gap-1.5 text-xs">
                {data.phone && (
                  <div className="flex items-center gap-2 text-muted-foreground">
                    <Phone className="h-3.5 w-3.5" />
                    <span>{data.phone}</span>
                  </div>
                )}
                {data.email && (
                  <div className="flex items-center gap-2 text-muted-foreground">
                    <Mail className="h-3.5 w-3.5" />
                    <span className="truncate">{data.email}</span>
                  </div>
                )}
                {data.website && (
                  <div className="flex items-center gap-2 text-muted-foreground">
                    <Globe className="h-3.5 w-3.5" />
                    <a
                      href={data.website}
                      target="_blank"
                      rel="noreferrer"
                      className="text-primary hover:underline truncate"
                    >
                      {data.website}
                    </a>
                  </div>
                )}
              </div>

              {/* Open full page */}
              <div className="pt-2 flex justify-end">
                <Button
                  asChild
                  variant="outline"
                  size="sm"
                >
                  <a
                    href={`/restaurants/${data.id}`}
                    target="_blank"
                    rel="noreferrer"
                  >
                    <ExternalLink className="h-3.5 w-3.5 mr-1" />
                    {t("admin.landmarkTagsPage.openDetail", "打开详情页")}
                  </a>
                </Button>
              </div>
            </div>
          </>
        )}
      </DialogContent>
    </Dialog>
  );
}
